import java.util.*;

public class MatrixTraversal {

    // 1. Spiral Order Traversal
    static List<Integer> spiralOrder(int[][] matrix) {
        List<Integer> result = new ArrayList<>();
        int top = 0, bottom = matrix.length - 1;
        int left = 0, right = matrix[0].length - 1;

        while (top <= bottom && left <= right) {
            for (int c = left;   c <= right;  c++) result.add(matrix[top][c]);
            for (int r = top+1;  r <= bottom; r++) result.add(matrix[r][right]);
            if (top < bottom)
                for (int c = right-1; c >= left; c--) result.add(matrix[bottom][c]);
            if (left < right)
                for (int r = bottom-1; r > top;  r--) result.add(matrix[r][left]);
            top++; bottom--; left++; right--;
        }
        return result;
    }

    // 2. Rotate Matrix 90° Clockwise (in-place)
    static void rotate(int[][] matrix) {
        int n = matrix.length;
        // Step 1: Transpose
        for (int i = 0; i < n; i++)
            for (int j = i + 1; j < n; j++) {
                int t = matrix[i][j]; matrix[i][j] = matrix[j][i]; matrix[j][i] = t;
            }
        // Step 2: Reverse each row
        for (int[] row : matrix) {
            int l = 0, r = n - 1;
            while (l < r) { int t = row[l]; row[l++] = row[r]; row[r--] = t; }
        }
    }

    // 3. Search in Row-and-Column Sorted Matrix (O(N+M))
    static boolean searchMatrix(int[][] matrix, int target) {
        int row = 0, col = matrix[0].length - 1; // start top-right
        while (row < matrix.length && col >= 0) {
            if (matrix[row][col] == target) return true;
            else if (matrix[row][col] > target) col--;  // too big, go left
            else row++;                                   // too small, go down
        }
        return false;
    }

    public static void main(String[] args) {
        int[][] m = {{1,2,3},{4,5,6},{7,8,9}};
        System.out.println(spiralOrder(m)); // [1,2,3,6,9,8,7,4,5]

        int[][] r = {{1,2,3},{4,5,6},{7,8,9}};
        rotate(r);
        System.out.println(Arrays.deepToString(r)); // [[7,4,1],[8,5,2],[9,6,3]]

        int[][] s = {{1,4,7,11},{2,5,8,12},{3,6,9,16},{10,13,14,17}};
        System.out.println(searchMatrix(s, 5));  // true
        System.out.println(searchMatrix(s, 20)); // false
    }
}
